import{_ as t,c as a,o,a1 as r}from"./chunks/framework.9hXSu8bi.js";const e="/mypatterndocs/static/%E8%A7%92%E8%89%B2%E7%AE%A1%E7%90%86%E4%BB%8B%E7%BB%8D.CDqvNd8r.png",m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/帮助文档/功能介绍/角色管理.md","filePath":"zh/帮助文档/功能介绍/角色管理.md"}'),s={name:"zh/帮助文档/功能介绍/角色管理.md"},n=r('<h2 id="角色管理" tabindex="-1">角色管理 <a class="header-anchor" href="#角色管理" aria-label="Permalink to &quot;角色管理&quot;">​</a></h2><blockquote><p>角色管理页面用于定义系统用户角色及权限，支持角色的增删改查，并可分别配置管理页面和三维页面的访问权限。</p></blockquote><p><img src="'+e+'" alt="" data-fancybox="gallery"></p><h3 id="_1-角色基本信息" tabindex="-1">1. 角色基本信息 <a class="header-anchor" href="#_1-角色基本信息" aria-label="Permalink to &quot;1. 角色基本信息&quot;">​</a></h3><ul><li><strong>角色名称</strong>：自定义的角色标识，如“管理员”“监测员”“访客”等。</li><li><strong>角色性质</strong>：角色的预设类型，分为“公共”和“私有”。</li><li><strong>备注</strong>：对角色的补充说明，如职责描述、适用范围等。</li><li><strong>创建时间</strong>：角色的创建日期，由系统自动记录。</li></ul><h3 id="_2-编辑角色" tabindex="-1">2. 编辑角色 <a class="header-anchor" href="#_2-编辑角色" aria-label="Permalink to &quot;2. 编辑角色&quot;">​</a></h3><ul><li><strong>新增</strong>：创建新的角色，填写角色名称、性质及备注。</li><li><strong>管理页面授权</strong>：为该角色分配后台管理页面的功能菜单访问权限。</li><li><strong>三维页面授权</strong>：为该角色分配三维监测页面的功能菜单访问权限。</li><li><strong>编辑</strong>：修改当前角色的名称和备注。</li><li><strong>删除</strong>：从系统中移除该角色（若角色已关联用户，则需先删除或修改该角色对应的用户）。</li></ul>',7),l=[n];function i(_,c,d,h,g,p){return o(),a("div",null,l)}const f=t(s,[["render",i]]);export{m as __pageData,f as default};
